import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-zlLwmkyI.js";var s={class:`ant-doc vp-doc`},c=a({__name:`skills.en-US`,setup(a,{expose:c}){let l={title:`Skills`,frontmatter:{title:`Skills`,tag:`New`},headers:[{level:2,title:`What are Agent Skills?`,slug:`what-are-agent-skills`,link:`#what-are-agent-skills`,children:[{level:3,title:`Why Use ProComponents of Vuents of Vue Skills?`,slug:`why-use-procomponents-of-vuents-of-vue-skills`,link:`#why-use-procomponents-of-vuents-of-vue-skills`,children:[]}]},{level:2,title:`How Skills Work`,slug:`how-skills-work`,link:`#how-skills-work`,children:[{level:3,title:`Three-Level Loading Mechanism`,slug:`three-level-loading-mechanism`,link:`#three-level-loading-mechanism`,children:[]}]},{level:2,title:`Installation`,slug:`installation`,link:`#installation`,children:[]},{level:2,title:`Usage`,slug:`usage`,link:`#usage`,children:[{level:3,title:`Usage Examples`,slug:`usage-examples`,link:`#usage-examples`,children:[]}]},{level:2,title:`Technical Implementation`,slug:`technical-implementation`,link:`#technical-implementation`,children:[{level:3,title:`Skill Structure`,slug:`skill-structure`,link:`#skill-structure`,children:[]},{level:3,title:`Generation Process`,slug:`generation-process`,link:`#generation-process`,children:[]}]},{level:2,title:`Supported AI Platforms`,slug:`supported-ai-platforms`,link:`#supported-ai-platforms`,children:[]},{level:2,title:`Contributing`,slug:`contributing`,link:`#contributing`,children:[]}],description:``},u={title:`Skills`,tag:`New`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>Agent Skills are modular capabilities that extend AI functionality. ProComponents of Vue Skills provide AI Agents with specialized knowledge of the ProComponents of Vue component library, enabling AI to accurately understand and use components.</p><h2 id="what-are-agent-skills" tabindex="-1">What are Agent Skills? <a class="header-anchor" href="#what-are-agent-skills" aria-label="Permalink to &quot;What are Agent Skills?&quot;">​</a></h2><p>Agent Skills are reusable, file-system based resources that provide AI Agents with domain-specific expertise: workflows, context, and best practices, transforming a general-purpose agent into an expert. Unlike prompts (which are conversation-level, one-time task instructions), <strong>Skills are loaded on-demand without needing to repeat the same guidance across multiple conversations</strong>.</p><h3 id="why-use-procomponents-of-vuents-of-vue-skills" tabindex="-1">Why Use ProComponents of Vuents of Vue Skills? <a class="header-anchor" href="#why-use-procomponents-of-vuents-of-vue-skills" aria-label="Permalink to &quot;Why Use ProComponents of Vuents of Vue Skills?&quot;">​</a></h3><p><strong>Key Benefits</strong>:</p><ul><li><strong>Specialize AI</strong>: Customize functionality for ProComponents of Vuents of Vue component development, making AI a component library expert</li><li><strong>Reduce Repetition</strong>: Create once, use automatically. No need to tell AI how to use components every time</li><li><strong>Compose Capabilities</strong>: Combine Skills to build complex component development workflows</li><li><strong>Reduce Hallucinations</strong>: Avoid AI generating non-existent Props or incorrect usage by providing real documentation and examples</li><li><strong>Offline Available</strong>: Skills localizes documentation content, ensuring stability and reliability without depending on external links</li></ul><h2 id="how-skills-work" tabindex="-1">How Skills Work <a class="header-anchor" href="#how-skills-work" aria-label="Permalink to &quot;How Skills Work&quot;">​</a></h2><p>Skills leverage AI Agent’s virtual machine environment to provide capabilities beyond what’s possible with prompts alone. AI Agents run in a virtual machine with file system access, allowing Skills to exist as directories containing instructions, executable code, and reference materials.</p><p>This file-system based architecture supports <strong>progressive disclosure</strong>: AI Agents load information on-demand in stages, rather than consuming context upfront.</p><h3 id="three-level-loading-mechanism" tabindex="-1">Three-Level Loading Mechanism <a class="header-anchor" href="#three-level-loading-mechanism" aria-label="Permalink to &quot;Three-Level Loading Mechanism&quot;">​</a></h3><p>Skills can contain three types of content, each loaded at different times:</p><table><thead><tr><th>Level</th><th>Load Time</th><th>Token Cost</th><th>Content</th></tr></thead><tbody><tr><td><strong>Level 1: Metadata</strong></td><td>Always (at startup)</td><td>~100 tokens</td><td><code>name</code> and <code>description</code> in YAML frontmatter</td></tr><tr><td><strong>Level 2: Instructions</strong></td><td>When Skill is triggered</td><td>&lt; 5k tokens</td><td>SKILL.md body with instructions and guidance</td></tr><tr><td><strong>Level 3: Resources</strong></td><td>On-demand</td><td>Virtually unlimited</td><td>Bundled files executed via bash, not loaded into context</td></tr></tbody></table><p><strong>What does this mean?</strong></p><ul><li>AI Agent only knows at startup that “there’s an ProComponents of Vuents of Vue Skill available to help with components”</li><li>When you request “create a Button component”, the AI loads the complete Button documentation</li><li>If documentation references example code, AI reads those files on-demand</li><li>Unused component documentation doesn’t consume any context</li></ul><blockquote><p>💡 <strong>Analogy</strong>: Like an onboarding guide for a new team member. They know the guide exists (metadata), open relevant chapters when needed (instructions), and consult detailed appendices when necessary (resources).</p></blockquote><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>:::success Important Note We recommend using ProComponents of Vuents of Vue Skill together with <a href="https://github.com/antfu/skills">Antfu’s Skills Collection</a> for better results. If you use <code>vue</code>, consider importing the <code>vue</code> skill and related skills to reduce AI hallucinations and ensure more standardized output! :::</p><p>Install the ProComponents of Vuents of Vue skill set via Skills CLI:</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">npx</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> skills</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> add</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> antdv-next/skills</span></span></code></pre></div><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>Once installed, AI Agents will <strong>automatically use</strong> Skills when you make requests related to ProComponents of Vuents of Vue components. For the most stable results, it’s recommended to explicitly declare:</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, &lt;your requirement&gt;</span></span></code></pre></div><p>This explicitly triggers the skill; otherwise, activation may be unstable due to insufficient matching.</p><h3 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to &quot;Usage Examples&quot;">​</a></h3><p><strong>Basic Component Development</strong>:</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, create a login page with form validation</span></span></code></pre></div><p><strong>Complex Interactions</strong>:</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, implement a data table with search, pagination, and filtering</span></span></code></pre></div><p><strong>Component Customization</strong>:</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, refactor the Button component according to AGENTS.md specifications, ensuring Props/Emits/Slots are correctly defined</span></span></code></pre></div><p><strong>Problem Diagnosis</strong>:</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, why isn&#39;t my Form component validation working?</span></span></code></pre></div><h2 id="technical-implementation" tabindex="-1">Technical Implementation <a class="header-anchor" href="#technical-implementation" aria-label="Permalink to &quot;Technical Implementation&quot;">​</a></h2><h3 id="skill-structure" tabindex="-1">Skill Structure <a class="header-anchor" href="#skill-structure" aria-label="Permalink to &quot;Skill Structure&quot;">​</a></h3><p>ProComponents of Vuents of Vue Skills follows the standard Skill structure:</p><div class="language-yaml ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">---</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">name</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">:</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> antdv-next</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">description</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">:</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> ProComponents of Vuents of Vue component library development expert...</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;"># ProComponents of Vuents of Vue Component Development</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## Quick Start</span></span>
<span class="line"><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">[</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">Component development workflow</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## API Conventions</span></span>
<span class="line"><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">[</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">Props/Emits/Slots specifications</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## Examples</span></span>
<span class="line"><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">For specific component usage, see [references/components/](references/components/)</span></span></code></pre></div><h3 id="generation-process" tabindex="-1">Generation Process <a class="header-anchor" href="#generation-process" aria-label="Permalink to &quot;Generation Process&quot;">​</a></h3><ol><li><strong>Documentation Extraction</strong>: Extract component documentation markdown files from the playground</li><li><strong>Example Conversion</strong>: Convert Vue SFC examples to markdown format</li><li><strong>Content Aggregation</strong>: Copy documentation and examples to the <code>references/</code> directory</li><li><strong>Metadata Generation</strong>: Create YAML frontmatter and main instructions</li><li><strong>Offline Optimization</strong>: Ensure all content is available offline without depending on external links</li></ol><p>The generation scripts support single-language output to reduce Skill size:</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> run</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> generate:en</span><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">  # Generate English version</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> run</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> generate:zh</span><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">  # Generate Chinese version</span></span></code></pre></div><h2 id="supported-ai-platforms" tabindex="-1">Supported AI Platforms <a class="header-anchor" href="#supported-ai-platforms" aria-label="Permalink to &quot;Supported AI Platforms&quot;">​</a></h2><p>ProComponents of Vuents of Vue Skills, as a <strong>custom Skill</strong>, can be used on multiple AI platforms:</p><ol><li>Claude Code</li><li>Codex</li><li>Github Copilot</li><li>Cursor</li><li>Antigravity</li><li>…</li></ol><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>This project is an <strong>early experiment</strong> aimed at providing specialized skills for AI Agents working with ProComponents of Vuents of Vue. Feedback via <a href="https://github.com/antdv-next/skills/issues">GitHub Issues</a> is welcome to help us improve coverage and accuracy.</p>`,45)]]))}});export{c as default};